mapper.select:
SELECT id, name, department_id, description, created_at
FROM gw_boards
WHERE id = #{id}

SELECT p.id, p.board_id, p.title, p.content, p.author_id, p.view_count, p.created_at, p.updated_at, u.name AS author_name, b.name AS board_name, (SELECT COUNT(*) FROM gw_comments c WHERE c.post_id = p.id) AS comment_count FROM gw_posts p JOIN itsm_users u ON p.author_id = u.id JOIN gw_boards b ON p.board_id = b.id WHERE p.board_id = #{boardId}
AND (p.title LIKE CONCAT('%', #{search}, '%') OR p.content LIKE CONCAT('%', #{search}, '%'))
ORDER BY p.created_at DESC LIMIT #{limit} OFFSET #{offset}
